var obj = CustomObjectMgr.searchByEnglishName('My Marker');
if(obj) {
    core.debug('Found custom object: ' + obj.getEnglishName());
} else {
    core.debug('Custom object not found');
}

// Add a marker at a specific J2000 position
var position = core.vec3d(0.5, 0.5, 0.707);
CustomObjectMgr.addCustomObject('My Marker', position, true);
core.debug('Custom marker added at position');

// Add an invisible custom object (for data storage)
var hiddenPos = core.vec3d(0.2, 0.3, 0.933);
CustomObjectMgr.addCustomObject('Hidden Object', hiddenPos, false);
core.debug('Hidden custom object added');

// Add a marker at Orion Nebula position
CustomObjectMgr.addCustomObject('Orion Nebula', '5h 35m 17.3s', '-5° 23′ 28″', true);
core.debug('Added Orion Nebula marker');

// Add a marker at Sirius position
CustomObjectMgr.addCustomObject('Sirius', '6h 45m 8.9s', '-16° 42′ 58″', true);
core.debug('Added Sirius marker');

// Add a marker using decimal degrees
CustomObjectMgr.addCustomObject('Galactic Center', '17h 45m 40s', '-29° 00′ 28″', true);
core.debug('Added Galactic Center marker');

// Verify marker count
var obj = CustomObjectMgr.searchByEnglishName('Orion Nebula');
if(obj) core.debug('Marker exists and can be found');

// Add a marker using current date coordinates
CustomObjectMgr.addCustomObjectRaDec('Current Position', '2h 10m 15s', '60d 01m 15s', true);
core.debug('Added marker at current date coordinates');

// Add a marker at the Sun's current position
var sunInfo = core.getObjectInfo('Sun');
CustomObjectMgr.addCustomObjectRaDec('Sun Now', sunInfo['ra'], sunInfo['dec'], true);
core.debug('Added marker at Sun\'s current position');

// Add a marker at zenith (directly overhead)
CustomObjectMgr.addCustomObjectAltAzi('Zenith', '90°', '0°', true);
core.debug('Added marker at zenith');

// Add a marker on the eastern horizon
CustomObjectMgr.addCustomObjectAltAzi('East Point', '0°', '90°', true);
core.debug('Added marker on eastern horizon');

// Add a marker at a specific point in the sky
CustomObjectMgr.addCustomObjectAltAzi('My Point', '45d', '135d', true);
core.debug('Added marker at 45° altitude, 135° azimuth');

// Clear all temporary markers
CustomObjectMgr.removeCustomObjects();
core.debug('All custom markers removed');

// Add some markers then clear them
CustomObjectMgr.addCustomObject('Marker 1', '2h', '30d', true);
CustomObjectMgr.addCustomObject('Marker 2', '4h', '45d', true);
core.debug('Added two markers');
core.wait(3);
CustomObjectMgr.removeCustomObjects();
core.debug('Markers cleared');

// Remove a specific marker by name
CustomObjectMgr.removeCustomObject('My Marker');
core.debug('Removed My Marker');

// Check if exists before removing
var obj = CustomObjectMgr.searchByEnglishName('Orion Nebula');
if(obj) {
    CustomObjectMgr.removeCustomObject('Orion Nebula');
    core.debug('Removed Orion Nebula marker');
} else {
    core.debug('Marker not found');
}

// Set markers to bright red
var red = core.vec3f(1.0, 0.0, 0.0);
CustomObjectMgr.setMarkersColor(red);
core.debug('Marker color changed to red');

// Set markers to cyan
var cyan = core.vec3f(0.0, 0.8, 0.9);
CustomObjectMgr.setMarkersColor(cyan);
core.debug('Marker color changed to cyan');

// Set markers to yellow
var yellow = core.vec3f(1.0, 1.0, 0.0);
CustomObjectMgr.setMarkersColor(yellow);
core.debug('Marker color changed to yellow');

// Small markers for minimal visual impact
CustomObjectMgr.setMarkersSize(3.0);
core.debug('Marker size set to 3 pixels');

// Large, visible markers for presentations
CustomObjectMgr.setMarkersSize(8.0);
core.debug('Marker size set to 8 pixels');

// Default size
CustomObjectMgr.setMarkersSize(5.0);
core.debug('Marker size reset to default (5 pixels)');

// Increase selection priority to make markers easily selectable
CustomObjectMgr.setSelectPriority(5.0);
core.debug('Custom object selection priority increased to 5.0');

// Lower priority (harder to select)
CustomObjectMgr.setSelectPriority(-10.0);
core.debug('Custom object selection priority lowered to -10.0');

// Default priority
CustomObjectMgr.setSelectPriority(-2.0);
core.debug('Custom object selection priority reset to default (-2.0)');

var priority = CustomObjectMgr.getSelectPriority();
core.debug('Current custom object select priority: ' + priority);

if(priority > 0) {
    core.debug('Custom objects have high selection priority');
} else if(priority < -5) {
    core.debug('Custom objects are difficult to select');
}

// Add a persistent star marker
var position = core.vec3d(0.5, 0.5, 0.707);
CustomObjectMgr.addPersistentObject('My Favorite Star', position, 'star');
core.debug('Added persistent star (saved to disk)');

// Add a persistent custom object
var nebulaPos = core.vec3d(0.2, 0.8, 0.566);
CustomObjectMgr.addPersistentObject('Discovered Nebula', nebulaPos, 'nebula');
core.debug('Added persistent nebula marker');

// Verify it was saved
var obj = CustomObjectMgr.searchByEnglishName('My Favorite Star');
if(obj) core.debug('Persistent object can be found in search');

// Remove all saved persistent objects
CustomObjectMgr.removePersistentObjects();
core.debug('All persistent objects removed from storage');

// Add and then remove a persistent object
var pos = core.vec3d(0.1, 0.2, 0.974);
CustomObjectMgr.addPersistentObject('Temp Marker', pos, 'marker');
core.debug('Temporary persistent object added');
core.wait(2);
CustomObjectMgr.removePersistentObjects();
core.debug('All persistent objects cleared');
